import heapq

class Solution:
    def minCost(self, nums, queries):
        n = len(nums)
        adj = [[] for _ in range(n)]
        for x in range(n):
            for y in range(n):
                if x != y:
                    adj[x].append((y, abs(nums[x] - nums[y])))
            best = None
            for y in (x - 1, x + 1):
                if 0 <= y < n:
                    d = abs(nums[x] - nums[y])
                    if best is None or d < best[0] or (d == best[0] and y < best[1]):
                        best = (d, y)
            if best is not None:
                adj[x].append((best[1], 1))

        def dijkstra(src):
            dist = [float('inf')] * n
            dist[src] = 0
            pq = [(0, src)]
            while pq:
                d, u = heapq.heappop(pq)
                if d > dist[u]:
                    continue
                for v, w in adj[u]:
                    nd = d + w
                    if nd < dist[v]:
                        dist[v] = nd
                        heapq.heappush(pq, (nd, v))
            return dist

        cache = {}
        ans = []
        for l, r in queries:
            if l not in cache:
                cache[l] = dijkstra(l)
            ans.append(cache[l][r])
        return ans

