class Solution:
    def minCost(self, nums, queries):
        n = len(nums)
        fw = [0] * (n - 1)
        bw = [0] * (n - 1)

        def closest(i):
            if i == 0:
                return 1
            if i == n - 1:
                return n - 2
            dl = nums[i] - nums[i - 1]
            dr = nums[i + 1] - nums[i]
            return i - 1 if dl <= dr else i + 1

        for i in range(n - 1):
            diff = nums[i + 1] - nums[i]
            fw[i] = 1 if closest(i) == i + 1 else diff
            bw[i] = 1 if closest(i + 1) == i else diff

        pref_fw = [0] * n
        pref_bw = [0] * n
        for i in range(n - 1):
            pref_fw[i + 1] = pref_fw[i] + fw[i]
            pref_bw[i + 1] = pref_bw[i] + bw[i]

        ans = []
        for l, r in queries:
            if l == r:
                ans.append(0)
            elif l < r:
                ans.append(pref_fw[r] - pref_fw[l])
            else:
                ans.append(pref_bw[l] - pref_bw[r])
        return ans

