var minCost = function(nums, queries) {
    const n = nums.length;
    function closest(i) {
        if (i === 0) return 1;
        if (i === n - 1) return n - 2;
        const dl = nums[i] - nums[i - 1];
        const dr = nums[i + 1] - nums[i];
        return dl <= dr ? i - 1 : i + 1;
    }
    const fw = new Array(n - 1).fill(0);
    const bw = new Array(n - 1).fill(0);
    for (let i = 0; i < n - 1; i++) {
        const diff = nums[i + 1] - nums[i];
        fw[i] = (closest(i) === i + 1) ? 1 : diff;
        bw[i] = (closest(i + 1) === i) ? 1 : diff;
    }
    const prefFw = new Array(n).fill(0);
    const prefBw = new Array(n).fill(0);
    for (let i = 0; i < n - 1; i++) {
        prefFw[i + 1] = prefFw[i] + fw[i];
        prefBw[i + 1] = prefBw[i] + bw[i];
    }
    const ans = [];
    for (const [l, r] of queries) {
        if (l === r) ans.push(0);
        else if (l < r) ans.push(prefFw[r] - prefFw[l]);
        else ans.push(prefBw[l] - prefBw[r]);
    }
    return ans;
};
